    while (currentStart < n) {
        val stack = ArrayDeque<Int>()
        var found = false
        for (i in currentStart until n) {
            while (stack.isNotEmpty() && weight[stack.last()] <= weight[i]) {
                stack.removeLast()
            }
            if (stack.isNotEmpty()) {
                count++
                currentStart = i + 1
                found = true
                break
            } else {
                stack.add(i)
            }
        }
        if (!found) {
            currentStart++
        }
    }
    return count
}
